		ip protocol icmp accept
		ip6 nexthdr ipv6-icmp accept
		tcp dport { 22, 111, 2379-2381, 6080, 6443, 9001, 9099-9100, 9103-9105, 9107-9108, 9258, 9443, 9637, 9978-9980, 10250, 10256-10259, 17697, 22623-22624, 30000-32767 } accept
